        JR Z,L_DE07                      ; $DE01  28 04
        XOR E                            ; $DE03  AB
        CP C                             ; $DE04  B9
        JR Z,L_DE0C                      ; $DE05  28 05
L_DE07:
        DEC HL                           ; $DE07  2B
        DJNZ L_DDFF                      ; $DE08  10 F5
